import json
import psycopg2
import os
import boto3
from botocore.exceptions import ClientError

def get_secret():
    secret_name = os.environ.get('DB_SECRET_NAME', 'prod/db/credentials')
    region_name = os.environ.get('AWS_REGION', 'us-east-1')
    
    session = boto3.session.Session()
    client = session.client(
        service_name='secretsmanager',
        region_name=region_name
    )
    
    try:
        get_secret_value_response = client.get_secret_value(
            SecretId=secret_name
        )
        secret = json.loads(get_secret_value_response['SecretString'])
        return secret
    except ClientError as e:
        raise e

def lambda_handler(event, context):
    try:
        secret = get_secret()
        
        db_host = secret.get('host', os.environ.get('DB_HOST'))
        db_port = secret.get('port', os.environ.get('DB_PORT', '5432'))
        db_name = secret.get('dbname', os.environ.get('DB_NAME'))
        db_user = secret.get('username', os.environ.get('DB_USER'))
        db_password = secret.get('password', os.environ.get('DB_PASSWORD'))
        
        conn = psycopg2.connect(
            host=db_host,
            port=db_port,
            database=db_name,
            user=db_user,
            password=db_password,
            sslmode='require',
            connect_timeout=5
        )
        
        cursor = conn.cursor()
        
        query = event.get('query', 'SELECT version();')
        params = event.get('params', [])
        
        cursor.execute(query, params)
        
        columns = [desc[0] for desc in cursor.description]
        results = []
        for row in cursor.fetchall():
            results.append(dict(zip(columns, row)))
        
        cursor.close()
        conn.close()
        
        return {
            'statusCode': 200,
            'body': json.dumps({
                'success': True,
                'data': results,
                'count': len(results)
            }, default=str)
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({
                'success': False,
                'error': 'Database query failed',
                'message': str(e)
            })
        }